import{_ as a,c as t,o,a2 as i}from"./chunks/framework.CIiVzG-O.js";const d=JSON.parse('{"title":"Privacy Choices","description":"","frontmatter":{},"headers":[],"relativePath":"guide/privacy-choices.md","filePath":"guide/privacy-choices.md","lastUpdated":1777014665000}'),s={name:"guide/privacy-choices.md"};function r(l,e,n,c,p,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="privacy-choices" tabindex="-1">Privacy Choices <a class="header-anchor" href="#privacy-choices" aria-label="Permalink to &quot;Privacy Choices&quot;">​</a></h1><p>This page describes how to submit privacy requests to Nicasa and what to expect.</p><h2 id="what-this-is-for" tabindex="-1">What this is for <a class="header-anchor" href="#what-this-is-for" aria-label="Permalink to &quot;What this is for&quot;">​</a></h2><p>Use this page to request access to personal data, request deletion, request portability, or to opt out of certain data uses (for example, &quot;Do Not Sell&quot; requests where applicable).</p><p>Note: Nicasa currently does not collect or store personal data (see the Privacy Policy). If you believe we have personal data about you, submit a request and we will investigate.</p><h2 id="how-to-submit-a-request" tabindex="-1">How to submit a request <a class="header-anchor" href="#how-to-submit-a-request" aria-label="Permalink to &quot;How to submit a request&quot;">​</a></h2><p>Provide the following information when making a request to help us process it efficiently:</p><ul><li>Your name</li><li>Contact email</li><li>Description of the request (access, deletion, portability, or opt-out)</li><li>Any identifiers that help us locate records (e.g. support ticket ID)</li></ul><p>Send requests to one of the following:</p><ul><li>Email: <a href="mailto:nicasa@w3cub.com" target="_blank" rel="noreferrer">nicasa@w3cub.com</a></li><li>Open a privacy issue: <a href="https://github.com/nicasa-app/nicasa-support/issues" target="_blank" rel="noreferrer">https://github.com/nicasa-app/nicasa-support/issues</a></li></ul><h2 id="response-time" tabindex="-1">Response time <a class="header-anchor" href="#response-time" aria-label="Permalink to &quot;Response time&quot;">​</a></h2><p>We aim to acknowledge and respond to valid requests within 30 days. If we need more time, we will notify you with an estimated timeframe.</p><h2 id="if-we-do-not-hold-personal-data" tabindex="-1">If we do not hold personal data <a class="header-anchor" href="#if-we-do-not-hold-personal-data" aria-label="Permalink to &quot;If we do not hold personal data&quot;">​</a></h2><p>Because Nicasa is designed to process images locally and not collect user data, many requests will be closed with a confirmation that no personal data is held. If you provide evidence that personal data was collected, we will investigate and take appropriate action.</p><h2 id="do-not-sell-opt-out" tabindex="-1">Do Not Sell / Opt-out <a class="header-anchor" href="#do-not-sell-opt-out" aria-label="Permalink to &quot;Do Not Sell / Opt-out&quot;">​</a></h2><p>If you are exercising a jurisdictional right (for example under CCPA/CPRA) to opt out of sale, and you believe we have sold your personal data, please describe the circumstances in your request. If we do not sell personal data, we will confirm that in our response.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you have questions about this process, contact <a href="mailto:nicasa@w3cub.com" target="_blank" rel="noreferrer">nicasa@w3cub.com</a> or open an issue at <a href="https://github.com/nicasa-app/nicasa-support/issues" target="_blank" rel="noreferrer">https://github.com/nicasa-app/nicasa-support/issues</a>.</p>',18)])])}const m=a(s,[["render",r]]);export{d as __pageData,m as default};
